#include <iostream>
#include <vector>
#include <algorithm>

const int N = 10010;
int a[N];

class Solution {
public:
    bool recover_max_heap(std::vector<int>& nums) {
        int n = nums.size();

        // The max heap property is satisfied by the given array.
        // We need to remove the root element and heapify the remaining array.
        int root = nums[0];
        nums.erase(nums.begin());
        max_heapify(nums, 0);
        nums.insert(nums.begin(), root);
        return true;
    }

    void max_heapify(std::vector<int>& nums, int i) {
        int largest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;

        if (left < nums.size() && nums[left] > nums[largest]) {
            largest = left;
        }

        if (right < nums.size() && nums[right] > nums[largest]) {
            largest = right;
        }

        if (largest != i) {
            // Swap the elements with a temporary variable
            int temp = nums[i];
            nums[i] = nums[largest];
            nums[largest] = temp;
            max_heapify(nums, largest);
        }
    }

    int get_parent(int i) {
        return (i - 1) / 2;
    }

    int get_left_child(int i) {
        return 2 * i + 1;
    }

    int get_right_child(int i) {
        return 2 * i + 2;
    }

    void print_heap(const std::vector<int>& nums) {
        for (const auto& num : nums) {
            std::cout << num << ' '; // BUG
        }
        std::cout << std::endl;
    }
};

int main() {
    Solution solution;
    std::vector<int> nums = {1, 5, 4, 3, 2};
